Def:
=Round(Min(Aggr(If(Aggr(RangeSum(Above(
if(vProgramMeasure='Volume', Num(Sum([Loan Amount]),'$#,##0'),
	if(vProgramMeasure='Units', Num(Count(distinct [Loan Number]),'#,##0'),
        if(vProgramMeasure='Buy Price', Num(Sum([Base Buy ($)]),'$#,##0'), 
        	if(vProgramMeasure='Sell Price', Num(Sum([Net Sell ($)]),'$#,##0'),
            	if(vProgramMeasure='Revenue', Num(Sum([Revenue]),'$#,##0'),
                	if(vProgramMeasure='Credits', Num(Sum([CD Lender Credits]),'$#,##0'),
                    	if(vProgramMeasure='Cures', Num(Sum([CD Applied Cure]),'$#,##0'),
                        	if(vProgramMeasure='WAC', Num(Sum([Loan Amount]*[Interest Rate])/Sum([Loan Amount]),'#,##0.000')
))))))))
/
if(vProgramMeasure='Volume', Num(Sum(TOTAL [Loan Amount]),'$#,##0'),
	if(vProgramMeasure='Units', Num(Count(distinct TOTAL [Loan Number]),'#,##0'),
        if(vProgramMeasure='Buy Price', Num(Sum(TOTAL [Base Buy ($)]),'$#,##0'), 
        	if(vProgramMeasure='Sell Price', Num(Sum(TOTAL [Net Sell ($)]),'$#,##0'),
            	if(vProgramMeasure='Revenue', Num(Sum(TOTAL [Revenue]),'$#,##0'),
                	if(vProgramMeasure='Credits', Num(Sum(TOTAL [CD Lender Credits]),'$#,##0'),
                    	if(vProgramMeasure='Cures', Num(Sum(TOTAL [CD Applied Cure]),'$#,##0'),
                        	if(vProgramMeasure='WAC', Num(Sum(TOTAL [Loan Amount]*[Interest Rate])/Sum(TOTAL [Loan Amount]),'#,##0.000')
))))))))
,0,RowNo())),([$(vProgramCategory)],(=
if(vProgramMeasure='Volume', Num(Sum([Loan Amount]),'$#,##0'),
	if(vProgramMeasure='Units', Num(Count(distinct [Loan Number]),'#,##0'),
        if(vProgramMeasure='Buy Price', Num(Sum([Base Buy ($)]),'$#,##0'), 
        	if(vProgramMeasure='Sell Price', Num(Sum([Net Sell ($)]),'$#,##0'),
            	if(vProgramMeasure='Revenue', Num(Sum([Revenue]),'$#,##0'),
                	if(vProgramMeasure='Credits', Num(Sum([CD Lender Credits]),'$#,##0'),
                    	if(vProgramMeasure='Cures', Num(Sum([CD Applied Cure]),'$#,##0'),
                        	if(vProgramMeasure='WAC', Num(Sum([Loan Amount]*[Interest Rate])/Sum([Loan Amount]),'#,##0.000')
))))))))
,Desc)))<=0.8,
if(vProgramMeasure='Volume', Num(Sum([Loan Amount]),'$#,##0'),
	if(vProgramMeasure='Units', Num(Count(distinct [Loan Number]),'#,##0'),
        if(vProgramMeasure='Buy Price', Num(Sum([Base Buy ($)]),'$#,##0'), 
        	if(vProgramMeasure='Sell Price', Num(Sum([Net Sell ($)]),'$#,##0'),
            	if(vProgramMeasure='Revenue', Num(Sum([Revenue]),'$#,##0'),
                	if(vProgramMeasure='Credits', Num(Sum([CD Lender Credits]),'$#,##0'),
                    	if(vProgramMeasure='Cures', Num(Sum([CD Applied Cure]),'$#,##0'),
                        	if(vProgramMeasure='WAC', Num(Sum([Loan Amount]*[Interest Rate])/Sum([Loan Amount]),'#,##0.000')
))))))))
),[$(vProgramCategory)])))

