Def:
aggr ( 
	if ( 
		$(eCCA_TVI_Score_13_Months) >= 120, 
	    Dual ('Top Tier', 1), 
        if (
	    	$(eCCA_TVI_Score_13_Months) >= 80, 
		      Dual ('Second Tier', 2), 
			if ( 
            	$(eCCA_TVI_Score_13_Months) >= 0, 		     
		        Dual ( 'Bottom Tier' , 3 ),
//                Dual ( 'Undefined', 4)
                null()
	    )
       ) 
	),
    [$(vCCA_ParetoDim)]
)

DefExpanded:
aggr ( 
	if ( 
		(
num (  ([CCA Scorecard Volume]/)*100   , '' )*
+
num ( ([CCA Scorecard Margin $]/)*100     , '' )*
+
num ( (Pow([CCA Scorecard TurnTime],-1)/*100)   , '$(vNumFormat)' )  *( $(eCCA_TVI_VolumeRating) /100)*$(vScorecardTurnTimeWeight)
+
$(eCCA_TVI_PullThroughRating) * ( $(eCCA_TVI_MarginRating)  /100)*$(vScorecardPullThroughWeight)
)
/
($(vScorecardVolumeWeight)+$(vScorecardMarginWeight)+$(vScorecardTurnTimeWeight)+$(vScorecardPullThroughWeight)) >= 120, 
	    Dual ('Top Tier', 1), 
        if (
	    	$(eCCA_TVI_Score_13_Months) >= 80, 
		      Dual ('Second Tier', 2), 
			if ( 
            	$(eCCA_TVI_Score_13_Months) >= 0, 		     
		        Dual ( 'Bottom Tier' , 3 ),
//                Dual ( 'Undefined', 4)
                null()
	    )
       ) 
	),
    [$(vCCA_ParetoDim)]
)

