	Aggr(
    {$<[CCA Scorecard TurnTime] *= {">0"},[Loan Officer]*=>}
    	Pow([CCA Scorecard TurnTime]
        ,-1),[Loan Officer]))

Sum({<Rolling4MonthFlag*={Yes}, DateType*={'Funding'}, [Consolidated Channels]*={'Retail'}, [Loan Officer Missing]*={0},[Loan Officer]={"=(
num ( ([CCA Scorecard Volume_ShortTerm]/)*100  , '' )*
// ([TVI Volume Rating_2Months]*
+
num ( ([CCA Scorecard Margin $_ShortTerm]/)*100     , '' )*
// [TVI Margin Rating_2Months]*
+
num ( (  Pow ( [CCA Scorecard TurnTime_ShortTerm], -1 ) /  *100)    , '' )  *( num ( ([CCA Scorecard Volume_ShortTerm]/)*100  , '' ) /100)*
// [TVI Turn Times Rating_2Months]*([TVI Volume Rating_2Months]/100)*
+
num ( ([CCA Scorecard PullThrough_ShortTerm]/)*100    , '' ) * ( num ( ([CCA Scorecard Margin $_ShortTerm]/)*100     , '' )  /100)*
// [TVI Pull Through Rating_2Months]*([TVI Margin Rating_2Months]/100)*
)
/
(+++) > 0"}>}Revenue)

=Avg({$<[CCA Scorecard PullThrough_ShortTerm] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[Loan Officer]*=>}
    	[CCA Scorecard PullThrough_ShortTerm]
        ,[Loan Officer]
    )
)

Def:
if(
	Sum(Aggr([CCA Current Production Check],$(vCCA_ScorecardAggrLevel)))<0,
    Null(),
	Avg(
    	Aggr(
        	Sum({<
            	Rolling13MonthFlag*={Yes}, 
                DateType*={Funding}, 
                [Consolidated Channels]*={'$(vCCA_ChannelGroup)'}, 
                $(vCCA_ScorecardMissingLevel)
                >}
                [Revenue$(vRevenueFieldNamePostfix)]),
			$(vCCA_ScorecardAggrLevel)
            )
       )
)

